1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
3	type QuoteInput = { customer: Customer; items: Item[] };
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_BASE = 25;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const FOLLOW_UP_DISCOUNT = 0.15;
18	const CURSE_SURCHARGE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	
22	export function quote(input: QuoteInput): { premium: number } {
23	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
24	
25	  let policyBase = 0;
26	  let itemSurcharges = 0;
27	  const componentCounts: Record<string, number> = {};
28	  for (const item of input.items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
31	    } else {
32	      const base = BASE_PREMIUMS[item.type];
33	      policyBase += base;
34	      if (item.cursed) {
35	        itemSurcharges += base * CURSE_SURCHARGE;
36	      }
37	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
38	        itemSurcharges += base * HIGH_ENCHANTMENT_SURCHARGE;
39	      }
40	    }
41	  }
42	  for (const count of Object.values(componentCounts)) {
43	    if (count === 3) {
44	      policyBase += 60;
45	    } else {
46	      policyBase += count * COMPONENT_BASE;
47	    }
48	  }
49	  let policyModifiers = 0;
50	  if (input.customer.previousContracts === 0) {
51	    policyModifiers += policyBase * FIRST_INSURANCE_SURCHARGE;
52	  } else if ((input.customer.previousContracts ?? 0) >= 1) {
53	    policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT;
54	  }
55	  const total = Math.ceil(policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE);
56	  return { premium: total };
57	}
58	
59	export function claim(_input: unknown): { payout: number } {
60	  return { payout: 0 };
61	}
